import {GiCongress} from 'react-icons/gi'
import {
    FacebookIcon,
    TwitterIcon,
    WhatsappIcon,

  } from "react-share";

class App extends Component {

    constructor(props) {
        super(props)
        this.state = {
            items : [],
            currentItem : {
                text : '' ,
                key : ''
        }
    }
}

    render() {

        const style = {
            margintop: '100px',
            marginleft: '300px'
        }


        return (   

            <div>
                <GiCongress  style={{color: 'aqua'}} className="congress"  size={100} />

            <div  className = "App">  

          <header>


              <form id = "ToDo-Form"  >

                  {/* <img style={{height:'200px' ,marginRight:'60px' }  } src= {X} alt="Hello" /> */}
                  <img className="Img" src= {X} alt="Hello" />
                  <br/>
                  <br/>

                  {/* <input type="text" placeholder="Enter text" 
                //   value = {this.state.currentItem.text} 
                //   onChange={this.handleInput} 
                /> */}
                  <button >Next</button>
                  <br/>
                  <FiShoppingCart className="cart" size={50}/>
                  <br/>


              </form>

          </header>

          <div className="App2" >
                  <TwitterIcon className="icons" size={42} round={true} />
                  <br/>
                  <FacebookIcon className="icons" size={42} round={true} />
                  <br/>
                  <WhatsappIcon  className="icons" size={42} round={true} />



          </div>

          </div> 
          </div>
        );
    }
}

export default App
